import React, { Component } from 'react';
import { BrowserRouter as Router, Route, Link } from 'react-router-dom';
import Home from 'components/Home';
import About from 'components/About';
import Projects from 'components/Projects';
import Impossible from 'components/Impossible';
import Playgrounds from 'components/Playgrounds';
import logo from './logo.svg';
import './App.scss';

import { connect } from 'react-redux';
import { setGoals } from 'actions';
import Firebase from 'services/firebase';
const firestore = Firebase.db();

const ROUTES = [
  { route: '/', name: 'Home' },
  { route: '/about', name: 'About' },
  { route: '/projects', name: 'Projects' },
  { route: '/impossible', name: 'Impossible List' },
  { route: '/playgrounds', name: 'React Playgrounds' }
];

class App extends Component {
  componentDidMount() {
    this.fetchGoals();
  }

  fetchGoals = () => {
    firestore.collection('goals').get().then(snapshot => {
      const goals = [];

      snapshot.forEach(doc => {
        goals.push(doc.data());
      });
      
      this.props.setGoals(goals);
    });
  }
  addGoal = async (type, goal, status) => {
    const docRef = await firestore.collection('goals').add({
      type,
      goal,
      status,
      completedAt: null,
      postName: null
    });

    console.log("Document written with ID: ", docRef.id);
    this.fetchGoals();
  }

  render() {
    const { goals } = this.props;

    return (
      <div className="App">
        <header className="App-header">
          <img
            src={logo}
            className="App-logo"
            alt="logo"
          />
        </header>
        <main className="App-main">
          <Router>
            <div>
              <nav className="navbar navbar-expand-lg navbar-dark bg-main">
                <div className="collapse navbar-collapse" id="navbarNav">
                  <ul className="navbar-nav">
                    {ROUTES.map(({ route, name }) => (
                      <li key={name} className="nav-item">
                        <Link to={route} className="nav-link">
                          {name}
                        </Link>
                      </li>
                    ))}
                  </ul>
                </div>
              </nav>

              <section className="content">      
                <Route path="/" exact component={Home} />
                <Route path="/about" component={About} />
                <Route path="/projects" component={Projects} />
                <Route path="/playgrounds" component={Playgrounds} />
                <Route
                  path="/impossible"
                  render={() => <Impossible goals={goals} addGoal={this.addGoal} />}
                />
              </section>
            </div>
          </Router>
        </main>
      </div>
    );
  }
}

const mapStateToProps = state => ({
  goals: state.goals
});

const mapDispatchToProps = dispatch => ({
  setGoals: goals => dispatch(setGoals(goals))
});

export default connect(
  mapStateToProps,
  mapDispatchToProps
)(App);
