import React, { Component } from 'react';
import List from 'components/common/List';
import Button from 'components/common/Button';
import './Impossible.scss';
// import { goals, goalTypes } from './list';

class Impossible extends Component {
  constructor(props) {
    super(props);
    this.state = {
      type: '',
      goal: '',
      status: ''
    };
  }
  
  render() {
    const { goals } = this.props;
    const {
      type,
      goal,
      status
    } = this.state;

    return (
      <div className="impossible">
        <form className="form-inline">
          <label className="sr-only" htmlFor="goalType">
            Type
          </label>
          <input
            type="text"
            className="form-control mb-2 mr-sm-2"
            id="type"
            placeholder="Type"
            value={type}
            onChange={(e) => this.setState({ type: e.target.value })}
          />
          <label className="sr-only" htmlFor="goal">
            Goal
          </label>
          <div className="input-group mb-2 mr-sm-2">
            <input
              type="text"
              className="form-control"
              id="goal"
              placeholder="Goal"
              value={goal}
              onChange={(e) => this.setState({ goal: e.target.value })}
            />
          </div>
          <div className="input-group mb-2 mr-sm-2">
            <input
              type="text"
              className="form-control"
              id="status"
              placeholder="Status"
              value={status}
              onChange={(e) => this.setState({ status: e.target.value })}
            />
          </div>
          <Button
            type="submit"
            onClick={(e) => {
              e.preventDefault();
              this.props.addGoal(type, goal, status);
              this.setState({ 
                type: '',
                goal: '',
                status: ''
               });
            }}
            theme="dark">
            Add Goal
          </Button>
        </form>

        <List
          headline="Impossible List"
          items={goals.map(({ goal, type }) => ({ name: goal, type: type }))}
        />
      </div>
    );
  }
}

export default Impossible;
